			GPUShaderModule* w = node::ObjectWrap::Unwrap<GPUShaderModule>( opts->Get( context, String::NewFromUtf8Literal( isolate, "module" ) ).ToLocalChecked().As<v8::Object>() );
			desc.module = w->handle_;
